import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import InternshipModal from "../components/InternshipModal";
import axios from "axios";
import { useAuth } from "../context/AuthContext";

export default function Internship() {
  const navigate = useNavigate();
  const { currentUser } = useAuth();
  const [appliedIds, setAppliedIds] = useState([]);
  const [internships, setInternships] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingInternship, setEditingInternship] = useState(null);

  // Fetch internships & applied internships on mount
  useEffect(() => {
    fetchInternships();
    if (currentUser?.role === "student") {
      fetchAppliedInternships();
    }
  }, []);

  const fetchInternships = async () => {
    try {
      const res = await axios.get("/api/internships");
      setInternships(res.data);
    } catch (err) {
      console.error("Error fetching internships:", err);
    }
  };

  const fetchAppliedInternships = async () => {
    try {
      const res = await axios.get(`/api/applications/user/${currentUser._id}`);
      setAppliedIds(res.data.map(app => app.internshipId));
    } catch (err) {
      console.error("Error fetching applied internships:", err);
    }
  };

  const handleApply = async (internshipId) => {
    try {
      await axios.post("/api/applications/apply", {
        internshipId,
        studentId: currentUser._id,
      });
      setAppliedIds(prev => [...prev, internshipId]);
    } catch (err) {
      console.error("Apply error:", err);
    }
  };

  const handleSave = async (data) => {
    if (editingInternship) {
      // PUT to backend (optional)
      try {
        await axios.put(`/api/internships/${editingInternship._id}`, data);
        setInternships((prev) =>
          prev.map((item) =>
            item._id === editingInternship._id ? { ...item, ...data } : item
          )
        );
      } catch (err) {
        console.error("Edit failed:", err);
      }
    } else {
      try {
        const res = await axios.post("/api/internships", data);
        setInternships((prev) => [...prev, res.data]);
      } catch (err) {
        console.error("Post failed:", err);
      }
    }
    setEditingInternship(null);
    setIsModalOpen(false);
  };

  const handleDelete = async (id) => {
    const confirm = window.confirm("Delete this internship?");
    if (confirm) {
      try {
        await axios.delete(`/api/internships/${id}`);
        setInternships((prev) => prev.filter((item) => item._id !== id));
      } catch (err) {
        console.error("Delete failed:", err);
      }
    }
  };

  return (
    <div className="p-4">
      <h2 className="text-2xl font-bold mb-4">Internships</h2>

      {(currentUser?.role === "admin" || currentUser?.role === "hr") && (
        <button
          onClick={() => {
            setEditingInternship(null);
            setIsModalOpen(true);
          }}
          className="bg-green-600 text-white px-4 py-2 rounded mb-4"
        >
          Post Internship
        </button>
      )}

      <div className="grid gap-4 md:grid-cols-2">
        {internships.map((internship) => (
          <div
            key={internship._id}
            className="border p-4 rounded shadow-md bg-white"
          >
            <h3 className="text-xl font-semibold">{internship.title}</h3>
            <p className="text-gray-600">{internship.company}</p>
            <p><strong>Category:</strong> {internship.category}</p>
            <p><strong>Location:</strong> {internship.location}</p>
            <p><strong>Mode:</strong> {internship.mode}</p>
            <p className="text-sm mt-2">{internship.description}</p>

            {/* Student: Apply */}
            {currentUser?.role === "student" && (
              <button
                onClick={() => handleApply(internship._id)}
                className={`mt-3 px-3 py-1 rounded text-white ${
                  appliedIds.includes(internship._id)
                    ? "bg-gray-400 cursor-not-allowed"
                    : "bg-blue-600 hover:bg-blue-700"
                }`}
                disabled={appliedIds.includes(internship._id)}
              >
                {appliedIds.includes(internship._id) ? "Applied" : "Apply"}
              </button>
            )}

            {/* Admin/HR: Edit/Delete */}
            {(currentUser?.role === "admin" || currentUser?.role === "hr") && (
              <div className="flex gap-2 mt-3">
                <button
                  onClick={() => {
                    setEditingInternship(internship);
                    setIsModalOpen(true);
                  }}
                  className="bg-yellow-500 text-white px-3 py-1 rounded"
                >
                  Edit
                </button>
                {currentUser?.role === "admin" && (
                  <button
                    onClick={() => handleDelete(internship._id)}
                    className="bg-red-600 text-white px-3 py-1 rounded"
                  >
                    Delete
                  </button>
                )}
              </div>
            )}
          </div>
        ))}
      </div>

      <InternshipModal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false);
          setEditingInternship(null);
        }}
        onSave={handleSave}
        editingInternship={editingInternship}
      />
    </div>
  );
}
